contexto:
Texto do contrato sob análise:
{{texto_contrato}}

Lado representado:
{{lado}}

Valor da operação:
{{valor}}

Setor da empresa-alvo:
{{setor}}

formato_saida:
Retorne JSON com o seguinte schema:

{
  "sumario_executivo": "string com 2 a 4 linhas",
  "red_flags": [
    {
      "dimensao": "string",
      "trecho_literal": "string",
      "classificacao": "alerta_informativo | ponto_de_negociacao | clausula_bloqueante",
      "justificativa": "string com 2 a 4 linhas",
      "recomendacao_ajuste": "string com 1 a 3 linhas"
    }
  ],
  "clausulas_esperadas_ausentes": [
    {
      "clausula": "string",
      "criticidade": "alta | media | baixa",
      "justificativa": "string"
    }
  ],
  "exposicoes_consolidadas": [
    "string descrevendo exposição em 1 linha"
  ],
  "lacunas_de_informacao": [
    "string descrevendo lacuna em 1 linha"
  ]
}
